async function bootstrapApp20260409() {
  try {
    bindElements();
    wireEvents();
    renderModeSwitch();
    renderRowOptions();
    renderPreviewGrid();
    renderCustomValueGrid();
    renderExtraTypeOptions();
    renderExtraPreviewGrid();
    renderFixedCourseButtons();
    renderFixedExtraButtons();
    renderExtraDynamicFields();
    renderSelectedCourse(null);
    renderModeInfo();
    renderPlanSection();
    updateActionStates();

    if (EMBEDDED_COURSE_DATA?.courses?.length) {
      try {
        applyDataset(EMBEDDED_COURSE_DATA, '内蔵初期データ（起動時フォールバック）');
        if (els.searchMeta) {
          els.searchMeta.textContent = '内蔵初期データで起動しました。追加の科目データを確認しています。';
        }
      } catch (error) {
        console.error('内蔵初期データの適用に失敗しました。', error);
      }
    }

    try {
      await loadDataset();
    } catch (error) {
      console.error('科目データの追加読込に失敗しました。', error);
      if (els.searchMeta && /読み込み中|起動しました/.test(els.searchMeta.textContent || '')) {
        els.searchMeta.textContent = '科目データの追加読込に失敗しました。内蔵データで継続します。';
      }
    }
  } catch (error) {
    showFatalStartupError20260409(error);
  }
}

function showFatalStartupError20260409(error) {
  console.error('アプリ初期化に失敗しました。', error);
  const meta = document.getElementById('searchMeta');
  if (meta) meta.textContent = 'アプリの初期化に失敗しました。';
  const info = document.getElementById('datasetInfo');
  if (info) {
    info.innerHTML = `<div><strong>エラー:</strong> ${escapeHtml(error?.message || String(error) || '不明なエラー')}</div><div><strong>対処:</strong> app.js を最新版に差し替えてください。</div>`;
  }
}

