function applyDataset(data, loadSource) {
  state.dataset = data;
  state.datasetLoadSource = loadSource || '';
  state.courses = state.dataset.courses || [];

  const count = state.dataset.meta?.count ?? state.courses.length;
  const sourceTag = state.datasetLoadSource ? `（${state.datasetLoadSource}）` : '';
  if (els.searchMeta) {
    els.searchMeta.textContent = `${state.courses.length} 件の科目データを読み込みました${sourceTag}。`;
  }
  const notes = (state.dataset.meta?.notes || []).map(text => escapeHtml(text)).join(' / ');
  const sourceUrl = escapeHtml(state.dataset.meta?.sourceUrl || '#');
  const courseListSourceUrl = escapeHtml(state.dataset.meta?.courseListSourceUrl || '#');
  const sourceParts = [
    `<div><strong>データ件数:</strong> ${count} 件</div>`,
    `<div><strong>読込元:</strong> ${escapeHtml(state.datasetLoadSource || '不明')}</div>`,
    `<div><strong>カリキュラム・マップ:</strong> <a href="${sourceUrl}" target="_blank" rel="noreferrer">公開 PDF</a></div>`
  ];
  if (state.dataset.meta?.courseListSourceUrl) {
    sourceParts.push(`<div><strong>開設授業科目一覧:</strong> <a href="${courseListSourceUrl}" target="_blank" rel="noreferrer">公式ページ</a></div>`);
  }
  sourceParts.push(`<div><strong>メモ:</strong> ${notes || 'なし'}</div>`);
  if (els.datasetInfo) {
    els.datasetInfo.innerHTML = sourceParts.join('');
  }

  renderSearchResults(searchCourses(els.searchInput?.value || ''));
  renderFixedCourseButtons();
  renderScheduleStatus();
  renderTimetablePanel();
  void loadScheduleDataset();
}

function selectCourse(course) {
  state.selectedCourse = cloneCourseSource(course);
  renderSelectedCourse(state.selectedCourse);
  recomputePreview();
  updateActionStates();
  renderTimetablePanel();
}

function renderSearchResults(courses) {
  if (!els.searchResults) return;
  if (!courses.length) {
    els.searchResults.innerHTML = '<div class="status status--warn">該当科目が見つかりません。</div>';
    return;
  }

  const fragment = document.createDocumentFragment();

  courses.forEach(course => {
    const card = document.createElement('article');
    card.className = 'result-card';

    const sourceKindLabel = course.sourceKind === 'exact8'
      ? 'カリキュラム・マップ由来'
      : (course.sourceKind === 'sequence'
        ? '非ゼロ列を自動補完'
        : (course.sourceKind === 'creditsOnly' ? '単位数ベースの初期配点' : 'カスタム'));
    const metaChips = [
      chip(course.code || 'コードなし'),
      chip(`単位 ${course.credits ?? '—'}`),
      chip(`合計 ${course.total ?? '—'} 点`),
      chip(sourceKindLabel)
    ].join('');

    const schedule = getCourseScheduleInfo(course);
    let scheduleHtml = '';
    if (schedule) {
      const lines = [
        `<div><strong>開講:</strong> ${escapeHtml(formatScheduleSummaryText(schedule))}</div>`,
        schedule.room ? `<div><strong>教室:</strong> ${escapeHtml(schedule.room)}</div>` : '',
        schedule.person ? `<div><strong>担当:</strong> ${escapeHtml(schedule.person)}</div>` : ''
      ].filter(Boolean).join('');
      scheduleHtml = `<div class="result-card__extra">${lines}</div>`;
    } else {
      const loadingText = state.scheduleStatus === 'loading'
        ? '開講時限データを読み込み中です。'
        : '開講時限データがまだありません。';
      scheduleHtml = `<div class="result-card__extra">${escapeHtml(loadingText)}</div>`;
    }

    card.innerHTML = `
      <div class="result-card__top">
        <div>
          <div class="result-card__code">${escapeHtml(course.code)}</div>
          <h3>${escapeHtml(course.nameJa)}</h3>
          <p>${escapeHtml(course.nameEn || '')}</p>
        </div>
        <button class="button button--primary" type="button">選択</button>
      </div>
      <div class="result-card__meta">${metaChips}</div>
      ${scheduleHtml}
    `;

    card.querySelector('button').addEventListener('click', () => selectCourse(course));
    fragment.appendChild(card);
  });

  els.searchResults.replaceChildren(fragment);
}

function renderFixedCourseButtons() {
  if (!els.fixedCourseButtons) return;
  els.fixedCourseButtons.innerHTML = '';
  FIXED_COURSE_ROWS.forEach(row => {
    const name = DEFAULT_ROW_NAMES[row];
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'button button--small';
    button.textContent = `${row}行: ${name}`;
    button.addEventListener('click', () => selectFixedCourseRow(row));
    els.fixedCourseButtons.appendChild(button);
  });
}

function selectFixedCourseRow(row) {
  const existing = getCurrentDraft().courseRows[row];
  if (existing) {
    editPlanRow(row);
    return;
  }

  const name = DEFAULT_ROW_NAMES[row];
  const matched = findCourseByNameOrAlias(name);
  state.selectedCourse = matched ? cloneCourseSource(matched) : {
    code: '',
    nameJa: name,
    nameEn: '',
    credits: 0,
    total: 0,
    points18: clonePoints18(ZERO_18),
    aliases: [name],
    sourceKind: 'manual'
  };
  state.previewPoints18 = clonePoints18(ZERO_18);
  renderSelectedCourse(state.selectedCourse);
  renderRowOptions(row);
  updatePreviewInputs();
  updateActionStates();
  renderTimetablePanel();
  setWorkbookStatus(`${row}行の固定科目を手動配点用に選択しました。`, currentStatusKindAfterChange());
}

function renderSelectedCourse(course) {
  if (!els.selectedCourseBox) return;
  if (!course) {
    els.selectedCourseBox.classList.add('empty');
    els.selectedCourseBox.innerHTML = 'まだ科目が選択されていません。';
    return;
  }

  const targetRow = Number((els.targetRow && els.targetRow.value) || '');
  const isFixedSelection = isFixedCourseRow(targetRow);
  const subline = [
    course.code || 'コード未設定',
    course.credits ? `${course.credits} 単位` : '',
    course.isExternal ? '他研究群科目' : 'システム情報工学研究群科目',
    isFixedSelection ? '固定行の手動配点' : ''
  ].filter(Boolean).join(' / ');

  let pointsHtml = '';
  if (Array.isArray(course?.points18) && course.points18.length === 18) {
    pointsHtml = `
      <div class="point8-item point8-item--wide">
        <span>元データ</span>
        <strong>18観点入力 / 合計 ${sumPoints18(course.points18)} 点</strong>
      </div>
    `;
  } else if (course.points8 && Object.keys(course.points8).length > 0) {
    pointsHtml = GROUP_CONFIG.map(group => `
      <div class="point8-item">
        <span>${escapeHtml(group.label)}</span>
        <strong>${asInt(course.points8[group.key])}</strong>
      </div>
    `).join('');
  } else if (Array.isArray(course.rawCompetenceValues) && course.rawCompetenceValues.length > 0) {
    pointsHtml = `
      <div class="point8-item point8-item--wide">
        <span>公開 PDF から読める非ゼロ配点列</span>
        <strong>${course.rawCompetenceValues.map(asInt).join(' / ')}</strong>
        <div class="help-text">不足差分を見ながら 8 コンピテンスへ補完し、その後 18 観点へ初期展開します。</div>
      </div>
    `;
  } else {
    pointsHtml = `
      <div class="point8-item point8-item--wide">
        <span>元データ</span>
        <strong>大学院スタンダード配点が未登録のため、単位数換算 ${asInt(resolveCourseTotal(course))} 点をもとに初期配点します</strong>
      </div>
    `;
  }

  const schedule = getCourseScheduleInfo(course);
  const scheduleHtml = schedule
    ? `
      <div class="selected-course__schedule">
        <div><strong>開講ターム・時限</strong> ${escapeHtml(formatScheduleSummaryText(schedule))}</div>
        ${schedule.room ? `<div><strong>教室</strong> ${escapeHtml(schedule.room)}</div>` : ''}
        ${schedule.person ? `<div><strong>担当</strong> ${escapeHtml(schedule.person)}</div>` : ''}
      </div>
    `
    : `
      <div class="selected-course__schedule">
        <div><strong>開講時限</strong> ${escapeHtml(state.scheduleStatus === 'loading' ? '読込中です。' : '未登録または取得前です。')}</div>
      </div>
    `;

  const badges = [
    chip(course.sourceKind === 'sequence' ? '自動補完対象' : (course.sourceKind === 'creditsOnly' ? '単位数ベース' : '元配点あり')),
    chip(`最終合計 ${asInt(resolveCourseTotal(course))} 点`)
  ].join('');

  els.selectedCourseBox.classList.remove('empty');
  els.selectedCourseBox.innerHTML = `
    <div class="result-card__code">${escapeHtml(course.code || 'カスタム')}</div>
    <h3>${escapeHtml(course.nameJa || '名称未設定')}</h3>
    <div class="muted">${escapeHtml(subline)}</div>
    <div class="selected-course__source">${badges}</div>
    ${scheduleHtml}
    <div class="points8">${pointsHtml}</div>
    <div class="help-text">${escapeHtml(isFixedSelection ? '固定行の特別研究は、必要に応じて18観点を手動で割り振ってください。' : '大学院スタンダードの公開カリキュラム・マップは 8 コンピテンス配点なので、下の 18 観点は初期案です。必要なら手動で修正してください。')}</div>
  `;
}

function renderRowOptions(selectedValue = null) {
  if (!els.targetRow) return;
  const maxRow = getSelectableMaxRow();
  const rawSelected = Number((selectedValue ?? els.targetRow.value) || FIRST_REGULAR_COURSE_ROW);
  const options = [];

  if (isFixedCourseRow(rawSelected)) {
    options.push(rawSelected);
  }

  for (let row = FIRST_REGULAR_COURSE_ROW; row <= maxRow; row += 1) {
    options.push(row);
  }

  const safeSelected = options.includes(rawSelected)
    ? rawSelected
    : Math.min(Math.max(FIRST_REGULAR_COURSE_ROW, rawSelected || FIRST_REGULAR_COURSE_ROW), maxRow);

  els.targetRow.innerHTML = '';
  options.forEach(row => {
    const option = document.createElement('option');
    option.value = String(row);
    option.textContent = getRowLabel(row);
    els.targetRow.appendChild(option);
  });
  els.targetRow.value = String(safeSelected);
}

function addSelectedCourseToDraft() {
  if (!state.selectedCourse) return;
  const fallbackRow = isFixedCourseRow(Number(els.targetRow?.value || '')) ? Number(els.targetRow.value) : FIRST_REGULAR_COURSE_ROW;
  const row = Number((els.targetRow && els.targetRow.value) || fallbackRow);
  getCurrentDraft().courseRows[row] = makePlanEntryFromSelection(row);
  renderRowOptions();
  selectNextAvailableRow(row);
  state.selectedCourse = null;
  state.previewPoints18 = clonePoints18(ZERO_18);
  renderSelectedCourse(null);
  updatePreviewInputs();
  renderPlanSection();
  setWorkbookStatus(`${MODE_CONFIG[state.currentMode].label}の ${row} 行を更新しました。${MODE_CONFIG[state.currentMode].canWrite ? 'まだ Excel へは反映していません。' : '履修計画モードなので Excel は更新していません。'}`, currentStatusKindAfterChange());
}

function selectNextAvailableRow(currentRow) {
  const maxRow = getSelectableMaxRow() + 1;
  const candidates = [];
  const startRow = Math.max(FIRST_REGULAR_COURSE_ROW, currentRow + 1);
  for (let row = startRow; row <= maxRow; row += 1) {
    candidates.push(row);
  }
  for (let row = FIRST_REGULAR_COURSE_ROW; row <= Math.max(FIRST_REGULAR_COURSE_ROW, currentRow); row += 1) {
    candidates.push(row);
  }
  const rows = getCurrentDraft().courseRows;
  const nextEmpty = candidates.find(row => !rows[row]) || maxRow;
  renderRowOptions(nextEmpty);
}

function renderPlanSection() {
  renderSyncStatus();
  renderPlanList();
  renderExtraList();
  renderTotalsTable();
  updateActionStates();
  renderTimetablePanel();
}

function renderPlanList() {
  const entries = getPlanEntries(getCurrentDraft().courseRows);
  if (!els.planList) return;
  if (!entries.length) {
    els.planList.innerHTML = '<div class="status status--muted">まだ授業科目ドラフトはありません。科目を選んで追加してください。</div>';
  } else {
    els.planList.innerHTML = entries.map(entry => {
      const total = sumPoints18(entry.points18);
      const isFixed = isFixedCourseRow(entry.row);
      const tags = [
        entry.code ? chip(entry.code) : '',
        isFixed ? chip('固定行') : (entry.isExternal ? chip('他研究群') : chip('シス情科目')),
        chip(`${entry.credits ? `${entry.credits} 単位 / ` : ''}${total} 点`)
      ].join('');
      const schedule = getCourseScheduleInfo(entry.sourceCourse || entry);
      const scheduleHtml = schedule
        ? `<div class="plan-card__schedule"><div><strong>開講</strong> ${escapeHtml(formatScheduleSummaryText(schedule))}</div>${schedule.room ? `<div><strong>教室</strong> ${escapeHtml(schedule.room)}</div>` : ''}</div>`
        : '';
      const controls = isFixed
        ? `
          <div class="actions-row actions-row--compact">
            <span class="badge plan-card__fixed">固定行</span>
            <button class="button button--small" type="button" data-action="edit" data-row="${entry.row}">編集</button>
            <button class="button button--small button--danger" type="button" data-action="remove" data-row="${entry.row}">クリア</button>
          </div>
        `
        : `
          <div class="actions-row actions-row--compact">
            <button class="button button--small" type="button" data-action="up" data-row="${entry.row}">上へ</button>
            <button class="button button--small" type="button" data-action="down" data-row="${entry.row}">下へ</button>
            <button class="button button--small" type="button" data-action="edit" data-row="${entry.row}">編集</button>
            <button class="button button--small button--danger" type="button" data-action="remove" data-row="${entry.row}">削除</button>
          </div>
        `;
      return `
        <article class="plan-card">
          <div class="plan-card__top">
            <div>
              <div class="plan-card__row">${entry.row}行</div>
              <h3>${escapeHtml(displayCourseName(entry))}</h3>
              <p>${escapeHtml(entry.nameEn || '')}</p>
              <div class="plan-card__meta">${tags}</div>
              ${scheduleHtml}
            </div>
            <div class="plan-card__total">${total} 点</div>
          </div>
          ${controls}
        </article>
      `;
    }).join('');

    els.planList.querySelectorAll('button[data-action="remove"]').forEach(button => {
      button.addEventListener('click', () => removePlanRow(Number(button.dataset.row)));
    });
    els.planList.querySelectorAll('button[data-action="edit"]').forEach(button => {
      button.addEventListener('click', () => editPlanRow(Number(button.dataset.row)));
    });
    els.planList.querySelectorAll('button[data-action="up"]').forEach(button => {
      button.addEventListener('click', () => movePlanRow(Number(button.dataset.row), -1));
    });
    els.planList.querySelectorAll('button[data-action="down"]').forEach(button => {
      button.addEventListener('click', () => movePlanRow(Number(button.dataset.row), +1));
    });
  }

  const draft = getCurrentDraft();
  const metrics = getMetrics(draft);
  if (els.planCourseCount) els.planCourseCount.textContent = String(entries.length);
  if (els.planCredits) els.planCredits.textContent = String(entries.reduce((sum, entry) => sum + Number(entry.credits || 0), 0));
  if (els.planPointsTotal) els.planPointsTotal.textContent = String(metrics.subtotalTotal);
  if (els.extraItemCount) els.extraItemCount.textContent = String((draft.extraItems || []).length);
  if (els.extraPointsTotal) els.extraPointsTotal.textContent = String(metrics.extraTotal);
  if (els.projectedTotal) els.projectedTotal.textContent = String(metrics.projectedTotal);
  if (els.unmetCount) els.unmetCount.textContent = `${metrics.unmetCount} / 18`;
}

function movePlanRow(row, delta) {
  const targetRow = row + delta;
  if (isFixedCourseRow(row) || targetRow < FIRST_REGULAR_COURSE_ROW) return;

  const draft = getCurrentDraft();
  const entries = clonePlanRows(draft.courseRows);
  const current = entries[row];
  if (!current) return;

  const swap = entries[targetRow];
  if (swap) {
    entries[row] = { ...swap, row };
  } else {
    delete entries[row];
  }
  entries[targetRow] = { ...current, row: targetRow };

  draft.courseRows = entries;
  renderRowOptions(targetRow);
  if (state.selectedCourse) {
    recomputePreview();
  }
  renderPlanSection();
  setWorkbookStatus('授業科目ドラフトの並びを更新しました。', currentStatusKindAfterChange());
}

function editPlanRow(row) {
  const entry = getCurrentDraft().courseRows[row];
  if (!entry) return;

  state.selectedCourse = entry.sourceCourse ? cloneCourseSource(entry.sourceCourse) : {
    code: entry.code,
    nameJa: entry.nameJa,
    nameEn: entry.nameEn,
    credits: entry.credits,
    total: sumPoints18(entry.points18),
    points18: clonePoints18(entry.points18),
    sourceKind: 'manual',
    aliases: [entry.nameJa, entry.nameEn].filter(Boolean)
  };
  state.previewPoints18 = clonePoints18(entry.points18);
  renderSelectedCourse(state.selectedCourse);
  renderRowOptions(row);
  updatePreviewInputs();
  updateActionStates();
  renderTimetablePanel();
  setWorkbookStatus(`${row}行の内容を編集フォームへ読み込みました。`, currentStatusKindAfterChange());
}

function renderScheduleStatus() {
  if (!els.scheduleStatus || !els.scheduleUpdated) return;
  let label = '未読込';
  let className = 'badge';
  if (state.scheduleStatus === 'loading') {
    label = '読込中';
    className = 'badge badge--pending';
  } else if (state.scheduleStatus === 'ready') {
    label = '利用可能';
    className = 'badge badge--ok';
  } else if (state.scheduleStatus === 'warn') {
    label = '一部未取得';
    className = 'badge badge--warn';
  }
  els.scheduleStatus.textContent = label;
  els.scheduleStatus.className = className;

  if (state.scheduleStatus === 'ready') {
    const updatedLabel = state.scheduleMeta?.updated ? `更新日 ${escapeHtml(String(state.scheduleMeta.updated))}` : '更新日未取得';
    const sourceLabel = state.scheduleMeta?.source ? ` / 読込元 ${escapeHtml(String(state.scheduleMeta.source))}` : '';
    els.scheduleUpdated.innerHTML = `alternative-tsukuba-kdb の大学院 KdB 参照データを利用中です。<br>${updatedLabel}${sourceLabel}`;
  } else {
    els.scheduleUpdated.textContent = state.scheduleMessage || '科目データの読込後に開講時限データを取得します。';
  }
}

function renderScheduleTermTabs() {
  if (!els.scheduleTermTabs) return;
  els.scheduleTermTabs.innerHTML = '';
  SCHEDULE_TERM_OPTIONS.forEach(term => {
    const button = document.createElement('button');
    button.type = 'button';
    button.textContent = term.label;
    button.className = term.code === state.activeTermCode ? 'is-active' : '';
    button.addEventListener('click', () => {
      state.activeTermCode = term.code;
      renderScheduleTermTabs();
      renderTimetablePanel();
    });
    els.scheduleTermTabs.appendChild(button);
  });
}

async function loadScheduleDataset() {
  if (!state.courses.length) return;
  if (state.scheduleStatus === 'loading' || state.scheduleStatus === 'ready') return;

  state.scheduleStatus = 'loading';
  state.scheduleMessage = `同じリポジトリの ${LOCAL_KDB_EXPECTED_PATH_20260409} を読み込んでいます。`;
  renderScheduleStatus();

  const allowedCodes = new Set(state.courses.map(course => String(course.code || '').trim()).filter(Boolean));
  const errors = [];

  for (const candidate of SCHEDULE_REMOTE_CANDIDATES) {
    try {
      const response = await fetch(candidate.url, { cache: 'force-cache' });
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }
      const payload = await response.json();
      if (!Array.isArray(payload?.subject)) {
        throw new Error('subject 配列が見つかりません');
      }

      state.scheduleMap = buildScheduleMapFromKdb(payload, allowedCodes);
      state.scheduleStatus = 'ready';
      state.scheduleMessage = '開講時限データの読み込みが完了しました。';
      state.scheduleMeta = {
        updated: payload.updated || '',
        source: candidate.label
      };
      renderScheduleStatus();
      renderSearchResults(searchCourses(els.searchInput?.value || ''));
      renderSelectedCourse(state.selectedCourse);
      renderPlanSection();
      return;
    } catch (error) {
      errors.push(`${candidate.label}: ${error.message}`);
    }
  }

  state.scheduleStatus = 'warn';
  state.scheduleMessage = `開講時限データを取得できませんでした。${errors.join(' / ')}`;
  state.scheduleMap = {};
  renderScheduleStatus();
  renderSearchResults(searchCourses(els.searchInput?.value || ''));
  renderTimetablePanel();
}

function buildScheduleMapFromKdb(payload, allowedCodes) {
  const map = {};
  (payload.subject || []).forEach(line => {
    if (!Array.isArray(line) || line.length < 7) return;
    const code = String(line[0] || '').trim();
    if (!code) return;
    if (allowedCodes?.size && !allowedCodes.has(code)) return;

    const termStr = String(line[5] || '').trim();
    const timeslotStr = String(line[6] || '').trim();
    const note = String(line[10] || '').trim();
    const parsed = parseScheduleInfoFromKdb(termStr, timeslotStr);

    map[code] = {
      code,
      name: String(line[1] || '').trim(),
      year: String(line[4] || '').trim(),
      termStr,
      timeslotStr,
      room: String(line[7] || '').trim(),
      person: String(line[8] || '').trim(),
      note,
      classMethods: extractScheduleClassMethods(note),
      slotsByTerm: parsed.slotsByTerm,
      specialKinds: parsed.specialKinds,
      hasRegularSlot: parsed.hasRegularSlot
    };
  });
  return map;
}

function parseScheduleInfoFromKdb(termStr, timeslotStr) {
  let termGroups = parseKdbTermGroups(termStr);
  const groupedTimeslotStr = termGroups.length === 1 ? String(timeslotStr || '').replace(/ /g, ',') : String(timeslotStr || '');
  const slotGroupStrings = groupedTimeslotStr ? groupedTimeslotStr.split(' ') : [];
  const slotTables = [];

  const specialKinds = {
    concentration: false,
    negotiable: false,
    asneeded: false,
    nt: false
  };

  slotGroupStrings.forEach(groupStr => {
    slotTables.push(createScheduleTableFromString(groupStr));
    specialKinds.concentration ||= groupStr.includes('集中');
    specialKinds.negotiable ||= groupStr.includes('応談');
    specialKinds.asneeded ||= groupStr.includes('随時');
    specialKinds.nt ||= groupStr.includes('NT');
  });

  if (slotTables.length === 1 && termGroups.length > 1) {
    termGroups = [[...new Set(termGroups.flat())]];
  }

  const slotsByTerm = {};
  termGroups.forEach((termCodes, index) => {
    const table = slotTables[index];
    if (!table) return;
    termCodes.forEach(termCode => {
      if (!slotsByTerm[termCode]) {
        slotsByTerm[termCode] = createEmptyScheduleTable();
      }
      mergeScheduleTable(slotsByTerm[termCode], table);
    });
  });

  return {
    slotsByTerm,
    specialKinds,
    hasRegularSlot: Object.keys(slotsByTerm).length > 0
  };
}

function parseKdbTermGroups(termStr) {
  const allSeasons = ['春', '夏', '秋', '冬'];
  const normalSeasons = ['春', '秋'];
  const getTermCodeFromSeason = (season, module) => (season === '春' ? 0 : 3) + (module === 'A' ? 0 : module === 'B' ? 1 : 2);

  const termGroups = [];
  let season = null;

  String(termStr || '').split(' ').forEach(groupStr => {
    const group = [];
    const chars = Array.from(groupStr);
    for (let i = 0; i < chars.length; i += 1) {
      const char = chars[i];
      const nextChar = chars[i + 1];

      if (char === '通' && nextChar === '年') {
        group.push(0, 1, 2, 3, 4, 5);
        continue;
      }

      if (allSeasons.includes(char)) {
        season = char;
      }

      if (season) {
        if (['A', 'B', 'C'].includes(char) && normalSeasons.includes(season)) {
          group.push(getTermCodeFromSeason(season, char));
        }
        if (char === '休') {
          group.push(allSeasons.indexOf(season) + 6);
        }
      }
    }
    termGroups.push(group);
  });

  return termGroups;
}

function createScheduleTableFromString(value) {
  const table = createEmptyScheduleTable();
  let dayArray = [];

  String(value || '').split(',').forEach(slotStr => {
    const dayStr = slotStr.replace(/[0-9-]/g, '');
    const days = dayStr
      .split('・')
      .filter(day => SCHEDULE_DAY_LABELS.includes(day))
      .map(day => SCHEDULE_DAY_LABELS.indexOf(day));

    if (days.length > 0) {
      dayArray = days;
    }

    const periodArray = [];
    const periodStr = slotStr.replace(/[^0-9-]/g, '');
    if (periodStr.includes('-')) {
      const [startRaw, endRaw] = periodStr.split('-');
      const start = Number(startRaw);
      const end = Number(endRaw);
      for (let period = Math.max(start, 0); period <= Math.min(end, SCHEDULE_PERIOD_TIMES.length); period += 1) {
        periodArray.push(period);
      }
    } else if (periodStr.length > 0) {
      periodArray.push(Number(periodStr));
    }

    if (periodStr.length > 0) {
      dayArray.forEach(day => {
        periodArray.forEach(period => {
          if (day >= 0 && day < SCHEDULE_DAY_LABELS.length && period >= 1 && period <= SCHEDULE_PERIOD_TIMES.length) {
            table[day][period - 1] = true;
          }
        });
      });
    }
  });

  return table;
}

function createEmptyScheduleTable() {
  return Array.from({ length: SCHEDULE_DAY_LABELS.length }, () => Array(SCHEDULE_PERIOD_TIMES.length).fill(false));
}

function mergeScheduleTable(target, source) {
  source.forEach((dayRow, dayIndex) => {
    dayRow.forEach((value, periodIndex) => {
      target[dayIndex][periodIndex] ||= Boolean(value);
    });
  });
}

function scheduleTableToCells(table) {
  const cells = [];
  (table || []).forEach((dayRow, dayIndex) => {
    dayRow.forEach((value, periodIndex) => {
      if (value) {
        cells.push({ dayIndex, periodIndex });
      }
    });
  });
  return cells;
}

function extractScheduleClassMethods(note) {
  return ['対面', 'オンデマンド', '同時双方向'].filter(label => String(note || '').includes(label));
}

function getCourseScheduleInfo(courseLike) {
  if (!courseLike) return null;
  if (courseLike.schedule && typeof courseLike.schedule === 'object') {
    return courseLike.schedule;
  }
  const code = String(courseLike.code || '').trim();
  if (code && state.scheduleMap?.[code]) {
    return state.scheduleMap[code];
  }
  return null;
}

function formatScheduleSummaryText(schedule) {
  if (!schedule) return '開講時限データなし';
  const parts = [];
  if (schedule.termStr) parts.push(schedule.termStr);
  if (schedule.timeslotStr) {
    parts.push(schedule.timeslotStr);
  } else {
    const specialText = formatSpecialScheduleKinds(schedule.specialKinds);
    if (specialText) {
      parts.push(specialText);
    }
  }
  return parts.join(' / ') || '開講時限データなし';
}

function formatSpecialScheduleKinds(specialKinds) {
  if (!specialKinds) return '';
  return [
    specialKinds.concentration ? '集中' : '',
    specialKinds.negotiable ? '応談' : '',
    specialKinds.asneeded ? '随時' : '',
    specialKinds.nt ? 'NT' : ''
  ].filter(Boolean).join('・');
}

function renderTimetablePanel() {
  if (!els.timetableGrid || !els.timetableSummary || !els.timetableUnscheduled) return;
  renderScheduleStatus();
  renderScheduleTermTabs();

  const timetableItems = buildTimetableItemsForTerm(state.activeTermCode);
  const cellMap = new Map();

  timetableItems.forEach(item => {
    item.cells.forEach(cell => {
      const key = `${cell.dayIndex}-${cell.periodIndex}`;
      if (!cellMap.has(key)) {
        cellMap.set(key, []);
      }
      cellMap.get(key).push(item);
    });
  });

  let conflictCellCount = 0;
  const bodyHtml = Array.from({ length: SCHEDULE_PERIOD_TIMES.length }, (_, periodIndex) => {
    const cellHtml = SCHEDULE_DAY_LABELS.map((dayLabel, dayIndex) => {
      const key = `${dayIndex}-${periodIndex}`;
      const items = cellMap.get(key) || [];
      if (items.length > 1) {
        conflictCellCount += 1;
      }
      const slotContent = items.length
        ? `<div class="timetable-slotlist">${items.map(item => {
            const classes = ['timetable-chip'];
            if (items.length > 1) classes.push('timetable-chip--conflict');
            if (item.kind === 'preview') classes.push('timetable-chip--preview');
            return `
              <div class="${classes.join(' ')}">
                <strong>${escapeHtml(item.shortLabel)}</strong>
                <div class="timetable-chip__meta">${escapeHtml(item.meta)}</div>
              </div>
            `;
          }).join('')}</div>`
        : '';
      return `<td class="timetable-slot">${slotContent}</td>`;
    }).join('');

    return `
      <tr>
        <th class="timetable-table__time">
          <strong>${periodIndex + 1}限</strong>
          <span>${escapeHtml(SCHEDULE_PERIOD_TIMES[periodIndex][0])}<br>${escapeHtml(SCHEDULE_PERIOD_TIMES[periodIndex][1])}</span>
        </th>
        ${cellHtml}
      </tr>
    `;
  }).join('');

  els.timetableGrid.innerHTML = `
    <table class="timetable-table">
      <thead>
        <tr>
          <th class="timetable-table__time">時限</th>
          ${SCHEDULE_DAY_LABELS.map(label => `<th>${escapeHtml(label)}</th>`).join('')}
        </tr>
      </thead>
      <tbody>${bodyHtml}</tbody>
    </table>
  `;

  const previewConflict = timetableItems.some(item => item.kind === 'preview' && item.hasConflict);
  const unscheduledItems = buildUnscheduledCourseItems();

  els.timetableSummary.innerHTML = `
    <div class="timetable-summary__stats">
      ${chip(`${SCHEDULE_TERM_OPTIONS.find(term => term.code === state.activeTermCode)?.label || 'ターム未設定'}表示`)}
      ${chip(`配置中 ${timetableItems.filter(item => item.kind === 'draft').length} 科目`)}
      ${conflictCellCount > 0 ? `<span class="badge badge--warn">重複セル ${conflictCellCount}</span>` : '<span class="badge badge--ok">重複なし</span>'}
      ${previewConflict ? '<span class="badge badge--warn">候補科目が重複します</span>' : (state.selectedCourse ? '<span class="badge badge--pending">候補科目をプレビュー中</span>' : '')}
    </div>
  `;

  if (unscheduledItems.length) {
    els.timetableUnscheduled.innerHTML = `
      <div class="subsection-title">時限未配置 / 集中・応談など</div>
      <div class="unscheduled-list">
        ${unscheduledItems.map(item => `
          <div class="unscheduled-chip">
            <strong>${escapeHtml(item.label)}</strong>
            <div class="unscheduled-chip__meta">${escapeHtml(item.reason)}</div>
          </div>
        `).join('')}
      </div>
    `;
  } else {
    els.timetableUnscheduled.innerHTML = '<div class="status status--ok">集中・応談・未登録以外の未配置科目はありません。</div>';
  }
}

function buildTimetableItemsForTerm(termCode) {
  const items = [];
  const draftEntries = getPlanEntries(getCurrentDraft().courseRows);

  draftEntries.forEach(entry => {
    const schedule = getCourseScheduleInfo(entry.sourceCourse || entry);
    const table = schedule?.slotsByTerm?.[termCode];
    if (!table) return;
    items.push({
      kind: 'draft',
      row: entry.row,
      code: entry.code || '',
      label: displayCourseName(entry),
      shortLabel: `${entry.row}行 ${displayCourseName(entry)}`,
      meta: schedule.room || schedule.person || formatScheduleSummaryText(schedule),
      cells: scheduleTableToCells(table)
    });
  });

  const preview = buildSelectedPreviewTimetableItem(termCode);
  if (preview) {
    items.push(preview);
  }

  const occupancy = new Map();
  items.forEach(item => {
    item.cells.forEach(cell => {
      const key = `${cell.dayIndex}-${cell.periodIndex}`;
      if (!occupancy.has(key)) {
        occupancy.set(key, []);
      }
      occupancy.get(key).push(item);
    });
  });
  items.forEach(item => {
    item.hasConflict = item.cells.some(cell => (occupancy.get(`${cell.dayIndex}-${cell.periodIndex}`) || []).length > 1);
  });

  return items;
}

function buildSelectedPreviewTimetableItem(termCode) {
  if (!state.selectedCourse) return null;
  const row = Number((els.targetRow && els.targetRow.value) || '');
  const existing = getCurrentDraft().courseRows[row];
  if (existing && courseNamesEquivalent(displayCourseName(existing), displayCourseName(state.selectedCourse))) {
    return null;
  }

  const schedule = getCourseScheduleInfo(state.selectedCourse);
  const table = schedule?.slotsByTerm?.[termCode];
  if (!table) return null;

  return {
    kind: 'preview',
    row: row || null,
    code: state.selectedCourse.code || '',
    label: displayCourseName(state.selectedCourse),
    shortLabel: `候補 ${displayCourseName(state.selectedCourse)}`,
    meta: schedule.room || schedule.person || formatScheduleSummaryText(schedule),
    cells: scheduleTableToCells(table),
    hasConflict: false
  };
}

function buildUnscheduledCourseItems() {
  const items = [];
  const draftEntries = getPlanEntries(getCurrentDraft().courseRows);

  draftEntries.forEach(entry => {
    const schedule = getCourseScheduleInfo(entry.sourceCourse || entry);
    if (schedule?.hasRegularSlot) return;
    items.push({
      label: `${entry.row}行 ${displayCourseName(entry)}`,
      reason: schedule ? (formatSpecialScheduleKinds(schedule.specialKinds) || '時限情報がありません') : (state.scheduleStatus === 'loading' ? '開講時限データを読込中です' : '開講時限データがありません')
    });
  });

  if (state.selectedCourse) {
    const row = Number((els.targetRow && els.targetRow.value) || '');
    const existing = getCurrentDraft().courseRows[row];
    if (!(existing && courseNamesEquivalent(displayCourseName(existing), displayCourseName(state.selectedCourse)))) {
      const schedule = getCourseScheduleInfo(state.selectedCourse);
      if (!schedule?.hasRegularSlot) {
        items.push({
          label: `候補 ${displayCourseName(state.selectedCourse)}`,
          reason: schedule ? (formatSpecialScheduleKinds(schedule.specialKinds) || '時限情報がありません') : (state.scheduleStatus === 'loading' ? '開講時限データを読込中です' : '開講時限データがありません')
        });
      }
    }
  }

  return items;
}

function isFixedCourseRow(row) {
  return FIXED_COURSE_ROWS.includes(Number(row));
}

/* === 2026-04 follow-up fixes === */
function getFixedCourseRowForCourse(courseLike) {
  if (!courseLike) return null;
  const code = String(courseLike.code || '').trim().toUpperCase();
  const names = [
    courseLike.nameJa,
    courseLike.nameEn,
    ...(Array.isArray(courseLike.aliases) ? courseLike.aliases : [])
  ].map(value => normalize(value)).filter(Boolean);

  const rowMap = [
    { row: 11, ja: '情報理工前期特別研究A', en: 'Research in Computer Science A', codes: ['0ALD512', '0ALD513'] },
    { row: 12, ja: '情報理工前期特別研究B', en: 'Research in Computer Science B', codes: ['0ALD514', '0ALD515'] },
    { row: 13, ja: '情報理工前期特別研究C', en: 'Research in Computer Science C', codes: ['0ALD516', '0ALD517'] },
    { row: 14, ja: '情報理工前期特別研究D', en: 'Research in Computer Science D', codes: ['0ALD518', '0ALD519'] }
  ];

  const matched = rowMap.find(item => {
    if (item.codes.includes(code)) return true;
    return names.includes(normalize(item.ja)) || names.includes(normalize(item.en));
  });
  return matched ? matched.row : null;
}

function findPreferredRegularTargetRow() {
  const currentRow = Number((els.targetRow && els.targetRow.value) || '');
  if (Number.isFinite(currentRow) && currentRow >= FIRST_REGULAR_COURSE_ROW && !isFixedCourseRow(currentRow)) {
    return currentRow;
  }

  const rows = getCurrentDraft().courseRows;
  const maxRow = getSelectableMaxRow() + 1;
  for (let row = FIRST_REGULAR_COURSE_ROW; row <= maxRow; row += 1) {
    if (!rows[row]) return row;
  }
  return Math.max(FIRST_REGULAR_COURSE_ROW, maxRow);
}

function selectCourse(course) {
  const fixedRow = getFixedCourseRowForCourse(course);
  state.selectedCourse = cloneCourseSource(course);

  if (fixedRow) {
    const existing = getCurrentDraft().courseRows[fixedRow];
    renderRowOptions(fixedRow);
    state.previewPoints18 = existing && courseNamesEquivalent(displayCourseName(existing), displayCourseName(state.selectedCourse))
      ? clonePoints18(existing.points18)
      : clonePoints18(ZERO_18);
    renderSelectedCourse(state.selectedCourse);
    updatePreviewInputs();
    updateActionStates();
    renderTimetablePanel();
    return;
  }

  const targetRow = findPreferredRegularTargetRow();
  renderRowOptions(targetRow);
  renderSelectedCourse(state.selectedCourse);
  recomputePreview();
  updateActionStates();
  renderTimetablePanel();
}

function renderSearchResults(courses) {
  if (!els.searchResults) return;
  if (!courses.length) {
    els.searchResults.innerHTML = '<div class="status status--warn">該当科目が見つかりません。</div>';
    return;
  }

  const fragment = document.createDocumentFragment();

  courses.forEach(course => {
    const card = document.createElement('article');
    card.className = 'result-card';

    const sourceKindLabel = course.sourceKind === 'exact8'
      ? 'カリキュラム・マップ由来'
      : (course.sourceKind === 'sequence'
        ? '非ゼロ列を自動補完'
        : (course.sourceKind === 'creditsOnly' ? '単位数ベースの初期配点' : 'カスタム'));
    const fixedRow = getFixedCourseRowForCourse(course);
    const metaChips = [
      chip(course.code || 'コードなし'),
      chip(`単位 ${course.credits ?? '—'}`),
      chip(`合計 ${course.total ?? '—'} 点`),
      chip(sourceKindLabel),
      fixedRow ? chip(`${fixedRow}行の固定科目`) : ''
    ].filter(Boolean).join('');

    const schedule = getCourseScheduleInfo(course);
    let scheduleHtml = '';
    if (schedule) {
      const lines = [
        `<div><strong>開講:</strong> ${escapeHtml(formatScheduleSummaryText(schedule))}</div>`,
        schedule.room ? `<div><strong>教室:</strong> ${escapeHtml(schedule.room)}</div>` : '',
        schedule.person ? `<div><strong>担当:</strong> ${escapeHtml(schedule.person)}</div>` : ''
      ].filter(Boolean);
      scheduleHtml = `<div class="result-card__extra">${lines.join('')}</div>`;
    } else if (state.scheduleStatus === 'loading') {
      scheduleHtml = '<div class="result-card__extra muted">開講時限データを読み込み中です。</div>';
    }

    const fixedNote = fixedRow
      ? `<div class="result-card__extra"><strong>配点:</strong> ${fixedRow}行の固定欄で手動配点します。</div>`
      : '';

    card.innerHTML = `
      <div class="result-card__body">
        <div>
          <strong>${escapeHtml(course.nameJa || course.nameEn || '名称未設定')}</strong>
          ${course.nameEn ? `<div class="muted">${escapeHtml(course.nameEn)}</div>` : ''}
        </div>
        <div class="chips">${metaChips}</div>
        ${scheduleHtml}
        ${fixedNote}
      </div>
      <div class="result-card__actions">
        <button type="button" class="button button--primary button--small">選択</button>
      </div>
    `;
    card.querySelector('button').addEventListener('click', () => selectCourse(course));
    fragment.appendChild(card);
  });

  els.searchResults.innerHTML = '';
  els.searchResults.appendChild(fragment);
}

async function loadScheduleDataset() {
  if (!state.courses.length) return;
  if (state.scheduleStatus === 'loading' || state.scheduleStatus === 'ready') return;

  state.scheduleStatus = 'loading';
  state.scheduleMessage = `同じリポジトリの ${LOCAL_KDB_EXPECTED_PATH_20260409} を読み込んでいます。`;
  renderScheduleStatus();

  const allowedCodes = new Set(state.courses.map(course => String(course.code || '').trim()).filter(Boolean));
  const errors = [];
  const candidates = [
    { url: './data/kdb-grad.json', label: '同梱 data/kdb-grad.json' },
    { url: 'data/kdb-grad.json', label: '同梱 data/kdb-grad.json (relative)' },
    ...SCHEDULE_REMOTE_CANDIDATES
  ];

  for (const candidate of candidates) {
    try {
      const response = await fetch(candidate.url, { cache: 'force-cache' });
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }
      const payload = await response.json();
      if (!Array.isArray(payload?.subject)) {
        throw new Error('subject 配列が見つかりません');
      }

      state.scheduleMap = buildScheduleMapFromKdb(payload, allowedCodes);
      state.scheduleStatus = 'ready';
      state.scheduleMessage = '開講時限データの読み込みが完了しました。';
      state.scheduleMeta = {
        updated: payload.updated || '',
        source: candidate.label
      };
      renderScheduleStatus();
      renderSearchResults(searchCourses(els.searchInput?.value || ''));
      renderSelectedCourse(state.selectedCourse);
      renderPlanSection();
      return;
    } catch (error) {
      errors.push(`${candidate.label}: ${error.message}`);
    }
  }

  state.scheduleStatus = 'warn';
  state.scheduleMessage = `開講時限データを取得できませんでした。${errors.join(' / ')}`;
  state.scheduleMap = {};
  renderScheduleStatus();
  renderSearchResults(searchCourses(els.searchInput?.value || ''));
  renderTimetablePanel();
}

